#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.blueprintWarnings)]
    public class BlueprintWarningsOptionToggle : OptionToggleDefinition
    {
        public BlueprintWarningsOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.blueprintWarnings);
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.blueprintWarnings, value);
            Global.Options.SaveOptions();
        }
    }
}
